+/*
+ * Character rendering with pixel art sprites.
+ * Each character is 16x24 pixels.
+ * Drawn with outlines, shading gradients, and distinct features.
+ * Types 0-8 correspond to different roles.
+ */
+
+const SPRITE_WIDTH = 16;
+const SPRITE_HEIGHT = 24;
+
+// Palette for shading and outlines
+const PALETTE = {
+  outline: '#222222',
+  shadingDark: '#444444',
+  shadingLight: '#bbbbbb',
+  white: '#ffffff',
+  black: '#000000',
+  red: '#d22b2b',
+  green: '#2bd252',
+  blue: '#2b66d2',
+  yellow: '#d2d22b',
+  purple: '#922bd2',
+  cyan: '#2bd2d2',
+  gray: '#888888',
+  brown: '#8b5a2b',
+};
+
+// Each character type has a draw function that draws pixel art at (x,y)
+// using ctx.fillRect for each pixel or group of pixels.
+
+function drawPixel(ctx, x, y, color) {
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, 1, 1);
+}
+
+function drawBlock(ctx, x, y, w, h, color) {
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, w, h);
+}
+
+// Draw outline pixels around a shape
+function drawOutline(ctx, pixels) {
+  ctx.fillStyle = PALETTE.outline;
+  pixels.forEach(([x, y]) => ctx.fillRect(x, y, 1, 1));
+}
